urlset:
{% for page in pages %}

    {{ page.url | url }}
    {% if page.meta.document_dates and page.meta.document_dates.dates and page.meta.document_dates.dates.updated %}
    {{ page.meta.document_dates.dates.updated | date('%%Y-%%m-%%d') }}
    {% elif page.meta.document_dates and page.meta.document_dates.dates and page.meta.document_dates.dates.created %}
    {{ page.meta.document_dates.dates.created | date('%%Y-%%m-%%d') }}
    {% endif %}

{% endfor %}
